#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdlib>

// This driver compiles the user's code, then runs it with specified inputs,
// capturing the output.
// NOTE: This is a simplified driver. In a real system, robust error handling,
// sandboxing, and precise output comparison would be implemented.

std::string run_test(const std::string& input_str, int test_num) {
    std::string input_filename = "input_" + std::to_string(test_num) + ".txt";
    std::string output_filename = "output_" + std::to_string(test_num) + ".txt";
    std::string executable_name = "user_program"; // Assuming the user's code is compiled to this

    // 1. Write input to a file
    std::ofstream input_file(input_filename);
    input_file << input_str;
    input_file.close();

    // 2. Execute the user's program with input redirection and capture output
    //    (Assumes user_program is already compiled)
    std::string command = "./" + executable_name + " < " + input_filename + " > " + output_filename;
    system(command.c_str());

    // 3. Read the output
    std::ifstream output_file(output_filename);
    std::stringstream buffer;
    buffer << output_file.rdbuf();
    output_file.close();

    // Clean up temp files (optional, but good practice)
    remove(input_filename.c_str());
    remove(output_filename.c_str());

    return buffer.str();
}

int main() {
    std::cout << "Driver expects user's program to be compiled as 'user_program'.\n";
    std::cout << "It will create input_X.txt, run './user_program < input_X.txt > output_X.txt', and read output_X.txt.\n";
    std::cout << "Actual test execution logic would be embedded here, calling run_test for each case.\n";
    return 0;
}
